class Solution {
public:
int maxSubArraySum(int A[], int n) {
int maxsum = A[0];
int currentSum = A[0];
for (int i = 1; i < n; i++) {
if (currentSum < 0) currentSum = A[i];
else currentSum += A[i];
maxsum = std::max(maxsum, currentSum);
}
return maxsum;
};
};

