solutions.python:
class Solution:
    def maxSubArraySum(self, A, n):
        maxsum = A[0]
        currentSum = A[0]
        for i in range(1, n):
            if currentSum < 0:
                currentSum = A[i]
            else:
                currentSum += A[i]
            maxsum = max(maxsum, currentSum)
        return maxsum

solutions.javascript:
function maxSubArraySum(A, n) {
  let maxsum = A[0];
  let currentSum = A[0];
  for (let i = 1; i < n; i++) {
    if (currentSum < 0) currentSum = A[i];
    else currentSum += A[i];
    maxsum = Math.max(maxsum, currentSum);
  }
  return maxsum;
}
